mapper.insert:
/*
	 SQL ID : LogUserConnDAO.insertLogUserConnState
	 설  명 : 사용자 접속 상태 저장
*/

INSERT INTO TB_LOG_USER_CONN_STAT (
	USER_ID
	, ACSR_GBNCD
	, SBJCT_ID
	, JOB_HSTRY_CD
	, CNTN_DVC_TYCD
	, SESS_ID
	, RGTR_IP
	, CNTN_DTTM
) VALUES (
	#{userId}
	, #{connGbn}
	, #{crsCreCd}
	, #{workLocCd}
	, #{deviceTypeCd}
	, #{sessionId}
	, #{regIp}
	, FN_DTTM()
)

mapper.update:
/*
	 SQL ID : LogUserConnDAO.updateLogUserConnState
	 설  명 : 사용자 접속 상태 수정
*/
UPDATE TB_LOG_USER_CONN_STAT SET
	ACSR_GBNCD = #{connGbn}
	, SBJCT_ID = #{crsCreCd}
	, JOB_HSTRY_CD = #{workLocCd}
	, CNTN_DVC_TYCD = #{deviceTypeCd}
	, SESS_ID = #{sessionId}
	, RGTR_IP = #{regIp}
	, CNTN_DTTM = FN_DTTM()
WHERE 1 = 1
	AND USER_ID = #{userId}

mapper.select:
/*
	 SQL ID : LogUserConnDAO.listTopLogUserConnState
	 설  명 : 과목 접속자 최신 목록 조회 
*/



) WHERE LINE_NO = #{listScale}
